import { useState, useMemo, useEffect, useRef } from 'react';
import { useSearchParams } from 'react-router-dom';
import {
  ChevronDown, Search,
  SlidersHorizontal, LayoutGrid, ArrowUpDown,
  Package, ChevronLeft, ChevronRight, Check
} from 'lucide-react';
import ProductCard from '../components/ui/ProductCard';
import { CATEGORIES } from '../utils/constants';
import pp from '../assets/images/pp.png';

// ─── DATA ─────────────────────────────────────────
const COLORS_LIST = [
  { name: 'Blanc', hex: '#FFFFFF' },
  { name: 'Noir', hex: '#000000' },
  { name: 'Bleu', hex: '#3B82F6' },
  { name: 'Rouge', hex: '#EF4444' },
  { name: 'Vert', hex: '#22C55E' },
  { name: 'Jaune', hex: '#EAB308' },
  { name: 'Rose', hex: '#EC4899' },
];

const SIZES = ['S', 'M', 'L', 'XL'];

const PRODUCT_NAMES = ['T-Shirt Zoro', 'Mug Anime', 'Sneakers Custom', 'Sweat Nature', 'Coque Phone', 'Sac Otaku'];
const PRODUCT_PRICES = [10000, 8000, 25000, 15000, 5000, 12000];

const MOCK_PRODUCTS = Array.from({ length: 24 }, (_, i) => ({
  id: i + 1,
  name: PRODUCT_NAMES[i % 6],
  price: PRODUCT_PRICES[i % 6],
  rating: 4.5,
  category: CATEGORIES[i % CATEGORIES.length].id,
  image: '/assets/images/product1.png',

  color: COLORS_LIST[i % COLORS_LIST.length].name,
  colorHex: COLORS_LIST[i % COLORS_LIST.length].hex,
  size: SIZES[i % SIZES.length],
}));

// ─── PARALLAX ─────────────────────────────────────
function useParallax(speed = 0.1) {
  const ref = useRef(null);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;

    const onScroll = () => {
      const rect = el.getBoundingClientRect();
      const offset =
        (window.innerHeight / 2 - rect.top - rect.height / 2) * speed;
      el.style.transform = `translateY(${offset}px)`;
    };

    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, [speed]);

  return ref;
}

// ─── UI ───────────────────────────────────────────
function FilterSection({ title, children }) {
  const [open, setOpen] = useState(true);

  return (
    <div style={{ marginBottom: 20 }}>
      <button onClick={() => setOpen(!open)} style={{ width: '100%', display: 'flex', justifyContent: 'space-between' }}>
        <b>{title}</b>
        <ChevronDown size={16} />
      </button>

      {open && <div style={{ marginTop: 10 }}>{children}</div>}
    </div>
  );
}

// ─── MAIN ─────────────────────────────────────────
export default function Catalogue() {
  const [searchParams] = useSearchParams();
  const searchQuery = searchParams.get('search') || '';

  const [filters, setFilters] = useState({
    category: [],
    color: [],
    size: []
  });

  const [sortBy, setSortBy] = useState('default');
  const [page, setPage] = useState(1);

  const PER_PAGE = 9;
  const parallaxRef = useParallax(0.05);

  const toggleFilter = (key, value) => {
    setFilters(prev => {
      const arr = prev[key];
      return {
        ...prev,
        [key]: arr.includes(value)
          ? arr.filter(v => v !== value)
          : [...arr, value]
      };
    });
  };

  // ─── FILTER LOGIC ───────────────────────────────
  const filtered = useMemo(() => {
    let p = [...MOCK_PRODUCTS];

    if (searchQuery) {
      p = p.filter(x =>
        x.name.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }

    if (filters.category.length) {
      p = p.filter(x =>
        filters.category.includes(x.category)
      );
    }

    if (filters.color.length) {
      p = p.filter(x =>
        filters.color.includes(x.color)
      );
    }

    if (filters.size.length) {
      p = p.filter(x =>
        filters.size.includes(x.size)
      );
    }

    if (sortBy === 'price-asc') p.sort((a, b) => a.price - b.price);
    if (sortBy === 'price-desc') p.sort((a, b) => b.price - a.price);

    return p;
  }, [filters, sortBy, searchQuery]);

  const paginated = filtered.slice((page - 1) * PER_PAGE, page * PER_PAGE);
  const totalPages = Math.ceil(filtered.length / PER_PAGE);

  return (
    <div>
      {/* HEADER */}
      <section style={{ textAlign: 'center' }}>
        <h1>Catalogue</h1>

        <div ref={parallaxRef}>
          <img src={pp} alt="" style={{ width: '100%', borderRadius: 20 }} />
        </div>
      </section>

      <div style={{ display: 'flex', gap: 20 }}>

        {/* SIDEBAR */}
        <aside style={{ width: 250 }}>
          <FilterSection title="Catégories">
            {CATEGORIES.map(c => (
              <div key={c.id}>
                <input
                  type="checkbox"
                  onChange={() => toggleFilter('category', c.id)}
                />
                {c.label}
              </div>
            ))}
          </FilterSection>

          {/* 🎨 COULEURS */}
          <FilterSection title="Couleurs">
            <div style={{ display: 'flex', gap: 10, flexWrap: 'wrap' }}>
              {COLORS_LIST.map(c => {
                const active = filters.color.includes(c.name);

                return (
                  <div
                    key={c.name}
                    onClick={() => toggleFilter('color', c.name)}
                    style={{
                      width: 30,
                      height: 30,
                      borderRadius: '50%',
                      background: c.hex,
                      border: active ? '3px solid blue' : '2px solid #ddd',
                      cursor: 'pointer',
                      position: 'relative'
                    }}
                  >
                    {active && (
                      <Check
                        size={14}
                        color={c.hex === '#FFFFFF' ? '#000' : '#FFF'}
                        style={{
                          position: 'absolute',
                          top: '50%',
                          left: '50%',
                          transform: 'translate(-50%, -50%)'
                        }}
                      />
                    )}
                  </div>
                );
              })}
            </div>
          </FilterSection>

          {/* 📏 TAILLES */}
          <FilterSection title="Tailles">
            {SIZES.map(s => {
              const active = filters.size.includes(s);

              return (
                <button
                  key={s}
                  onClick={() => toggleFilter('size', s)}
                  style={{
                    margin: 5,
                    padding: 8,
                    border: active ? '2px solid blue' : '1px solid #ccc'
                  }}
                >
                  {s}
                </button>
              );
            })}
          </FilterSection>
        </aside>

        {/* PRODUITS */}
        <div style={{ flex: 1 }}>
          <div style={{ marginBottom: 20 }}>
            <select onChange={e => setSortBy(e.target.value)}>
              <option value="default">Pertinence</option>
              <option value="price-asc">Prix ↑</option>
              <option value="price-desc">Prix ↓</option>
            </select>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 20 }}>
            {paginated.map(p => (
              <ProductCard key={p.id} product={p} />
            ))}
          </div>

          {/* PAGINATION */}
          <div style={{ marginTop: 30 }}>
            <button onClick={() => setPage(p => p - 1)} disabled={page === 1}>
              <ChevronLeft />
            </button>

            {Array.from({ length: totalPages }, (_, i) => (
              <button key={i} onClick={() => setPage(i + 1)}>
                {i + 1}
              </button>
            ))}

            <button onClick={() => setPage(p => p + 1)} disabled={page === totalPages}>
              <ChevronRight />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
